document.addEventListener('DOMContentLoaded', function() {
    const portfolioData = {
        currentFilter: 'all',
        accounts: [
            {
                id: '001xx000003DHPi',
                name: 'Acme Corporation',
                healthScore: 'At Risk',
                healthColor: 'red',
                lastActivity: '15 days ago',
                openCases: 3,
                highPriorityCases: 1,
                overdueTasks: 2,
                pipeline: '$450K',
                risks: ['warning', 'clock', 'priority']
            },
            {
                id: '001xx000003DHPj',
                name: 'Global Industries',
                healthScore: 'Needs Attention',
                healthColor: 'yellow',
                lastActivity: '3 days ago',
                openCases: 1,
                highPriorityCases: 0,
                overdueTasks: 0,
                pipeline: '$280K',
                risks: []
            },
            {
                id: '001xx000003DHPk',
                name: 'Tech Solutions Inc',
                healthScore: 'Healthy',
                healthColor: 'green',
                lastActivity: 'Today',
                openCases: 0,
                highPriorityCases: 0,
                overdueTasks: 0,
                pipeline: '$750K',
                risks: []
            },
            {
                id: '001xx000003DHPl',
                name: 'Enterprise Corp',
                healthScore: 'Healthy',
                healthColor: 'green',
                lastActivity: '1 day ago',
                openCases: 2,
                highPriorityCases: 0,
                overdueTasks: 0,
                pipeline: '$920K',
                risks: []
            }
        ]
    };

    // Filter button handlers
    const filterButtons = document.querySelectorAll('[data-filter]');
    filterButtons.forEach(button => {
        button.addEventListener('click', function() {
            const filter = this.dataset.filter;
            portfolioData.currentFilter = filter;

            // Update button states
            filterButtons.forEach(btn => {
                btn.className = 'slds-button slds-button_neutral';
            });
            this.className = 'slds-button slds-button_brand';

            // Filter accounts (simplified - just show/hide for demo)
            const rows = document.querySelectorAll('.account-row');
            rows.forEach(row => {
                if (filter === 'all') {
                    row.style.display = '';
                } else {
                    const healthBadge = row.querySelector('.health-badge');
                    const healthText = healthBadge ? healthBadge.textContent.toLowerCase() : '';

                    let shouldShow = false;
                    if (filter === 'at-risk' && healthText.includes('at risk')) shouldShow = true;
                    if (filter === 'needs-attention' && healthText.includes('needs attention')) shouldShow = true;
                    if (filter === 'healthy' && healthText.includes('healthy')) shouldShow = true;

                    row.style.display = shouldShow ? '' : 'none';
                }
            });
        });
    });

    // Account row click handlers
    const accountRows = document.querySelectorAll('.account-row');
    accountRows.forEach(row => {
        row.addEventListener('click', function() {
            const accountId = this.dataset.id;
            const modal = document.querySelector('.account-modal');
            if (modal) {
                modal.style.display = 'block';
                document.body.style.overflow = 'hidden';
            }
        });
    });

    // Modal close handlers
    const closeModalBtn = document.getElementById('close-modal-btn');
    const modalCloseBtn = document.getElementById('modal-close-btn');

    function closeModal() {
        const modal = document.querySelector('.account-modal');
        if (modal) {
            modal.style.display = 'none';
            document.body.style.overflow = '';
        }
    }

    if (closeModalBtn) {
        closeModalBtn.addEventListener('click', closeModal);
    }
    if (modalCloseBtn) {
        modalCloseBtn.addEventListener('click', closeModal);
    }

    // Refresh button handler
    const refreshBtn = document.getElementById('refresh-btn');
    if (refreshBtn) {
        refreshBtn.addEventListener('click', function() {
            const spinner = document.querySelector('.loading-spinner');
            const content = document.querySelector('.portfolio-content');

            if (spinner && content) {
                spinner.style.display = 'block';
                content.style.display = 'none';

                setTimeout(() => {
                    spinner.style.display = 'none';
                    content.style.display = 'block';
                }, 1000);
            }
        });
    }

    // Account link handlers
    const accountLinks = document.querySelectorAll('a[data-id]');
    accountLinks.forEach(link => {
        link.addEventListener('click', function(e) {
            e.preventDefault();
            e.stopPropagation();
            console.log('Navigate to account:', this.dataset.id);
        });
    });
});

preview_css:
.portfolio-dashboard {
    padding: 1rem;
}

/* KPI Cards */
.kpi-card-danger {
    border-left: 4px solid #ea001e;
}

.kpi-card-warning {
    border-left: 4px solid #ffb75d;
}

.kpi-card-success {
    border-left: 4px solid #2e844a;
}

/* Health Badges */
.health-badge {
    padding: 0.25rem 0.5rem;
    border-radius: 0.25rem;
    font-weight: 600;
    font-size: 0.75rem;
}

.health-badge--red {
    background-color: #feded8;
    color: #ba0517;
}

.health-badge--yellow {
    background-color: #fef3cd;
    color: #856404;
}

.health-badge--green {
    background-color: #d4edda;
    color: #155724;
}

.health-badge--gray {
    background-color: #f3f3f3;
    color: #706e6b;
}

/* Account Row */
.account-row {
    cursor: pointer;
    transition: background-color 0.1s ease-in-out;
}

.account-row:hover {
    background-color: #f3f3f3;
}

/* Responsive Table */
@media (max-width: 48em) {
    .slds-table_bordered thead {
        display: none;
    }

    .slds-table_bordered tr {
        display: block;
        margin-bottom: 1rem;
        border: 1px solid #dddbda;
    }

    .slds-table_bordered td {
        display: block;
        text-align: right;
        padding-left: 50%;
        position: relative;
    }

    .slds-table_bordered td::before {
        content: attr(data-label);
        position: absolute;
        left: 0.75rem;
        font-weight: bold;
        text-align: left;
    }
}

/* Loading spinner animation */
.slds-spinner {
    position: relative;
    width: 2rem;
    height: 2rem;
    margin: 2rem auto;
}

.slds-spinner__dot-a,
.slds-spinner__dot-b {
    width: 0.5rem;
    height: 0.5rem;
    border-radius: 100%;
    background-color: #0176d3;
    position: absolute;
    animation: slds-spinner-dot 2s infinite ease-in-out;
}

.slds-spinner__dot-b {
    top: auto;
    bottom: 0;
    animation-delay: -1s;
}

@keyframes slds-spinner-dot {
    0%, 80%, 100% {
        transform: scale(0);
    }
    40% {
        transform: scale(1);
    }
}

/* Icon placeholders */
.slds-icon {
    width: 1rem;
    height: 1rem;
    fill: currentColor;
}

.slds-icon_medium {
    width: 1.5rem;
    height: 1.5rem;
}

.slds-icon_small {
    width: 1rem;
    height: 1rem;
}

.slds-icon_x-small {
    width: 0.75rem;
    height: 0.75rem;
}

.slds-icon-text-error {
    color: #ea001e;
}

.slds-icon-text-warning {
    color: #ffb75d;
}

/* Button icon spacing */
.slds-button__icon_left {
    margin-right: 0.25rem;
}

/* Modal backdrop */
.slds-backdrop {
    position: fixed;
    top: 0;
    right: 0;
    bottom: 0;
    left: 0;
    background: rgba(126, 140, 153, 0.8);
    z-index: 9000;
}

.slds-modal {
    position: fixed;
    top: 0;
    right: 0;
    bottom: 0;
    left: 0;
    z-index: 9001;
    display: flex;
    justify-content: center;
    align-items: center;
}

.slds-modal__container {
    position: relative;
    transform: translate(0, 0);
    background: #fff;
    border-radius: 0.25rem;
    box-shadow: 0 2px 25px 0 rgba(0, 0, 0, 0.1);
    max-height: 90vh;
    overflow: hidden;
    display: flex;
    flex-direction: column;
}

.slds-modal_large .slds-modal__container {
    width: 90%;
    max-width: 800px;
}

.slds-modal__header {
    position: relative;
    border-bottom: 1px solid #dddbda;
    border-radius: 0.25rem 0.25rem 0 0;
    background: #fff;
    text-align: center;
    padding: 1rem 1rem 0.75rem;
}

.slds-modal__close {
    position: absolute;
    top: 0.5rem;
    right: 0.5rem;
}

.slds-modal__content {
    overflow-y: auto;
    flex: 1 1 auto;
}

.slds-modal__footer {
    border-top: 1px solid #dddbda;
    border-radius: 0 0 0.25rem 0.25rem;
    background: #fff;
    text-align: right;
    padding: 0.75rem 1rem;
}
